@RestController
public class OAuthController {

    private static final Map<String, RegisteredClient> clients = new HashMap<>();

    @Autowired
    private TokenStore tokenStore;

    @GetMapping("/oauth/authorize")
    public String authorize(@RequestParam("client_id") String clientId,
                            @RequestParam("redirect_uri") String redirectUri,
                            Model model) {
        if (!isValidRedirectUri(redirectUri, clients.get(clientId))) {
            return "Invalid redirect URI";
        }

        AuthorizationCode code = new AuthorizationCode();
        // Generate authorization code
        storeAuthorizationCode(code);

        model.addAttribute("client_id", clientId);
        model.addAttribute("code", code.getCode());
        
        return "redirect:" + redirectUri + "?code=" + code.getCode() + "&state=123456";
    }
    
    private boolean isValidRedirectUri(String uri, RegisteredClient client) {
        String baseUri = client.getBaseUrl();
        int lastSlashIndex = baseUri.lastIndexOf('/');
        if (lastSlashIndex != -1) {
            baseUri = baseUri.substring(0, lastSlashIndex + 1);
        }

        return uri.startsWith(baseUri) || uri.equals(client.getBaseUrl());
    }
}

